HYPOTHESIS_000016_AUTOGLUON_001_PY_B59B1C04C4_SOURCE = 'import numpy as np\nimport pandas as pd\n\n\nNUMERIC_COLUMNS = (\n    "sleep_duration",\n    "heart_rate",\n    "bmi",\n    "calorie_expenditure",\n    "step_count",\n    "exercise_duration",\n    "water_intake",\n)\n\nTRAIN_ID_MAX = 690087\nEPSILON = 1e-6\n\n\ndef _as_numeric_series(raw, column):\n    if column in raw.columns:\n        return pd.to_numeric(raw[column], errors="coerce")\n    return pd.Series(np.nan, index=raw.index, dtype="float64")\n\n\ndef _is_multiple(series, step):\n    values = series.to_numpy(dtype="float64", copy=False)\n    out = np.zeros(len(series), dtype=bool)\n    mask = np.isfinite(values)\n    if mask.any():\n        ratio = values[mask] / step\n        out[mask] = np.abs(ratio - np.round(ratio)) <= EPSILON\n    return pd.Series(out, index=series.index)\n\n\ndef _decimal_tiers(series):\n    values = series.to_numpy(dtype="float64", copy=False)\n    finite = np.isfinite(values)\n\n    integer_like = np.zeros(len(series), dtype=bool)\n    one_decimal_like = np.zeros(len(series), dtype=bool)\n    two_decimal_like = np.zeros(len(series), dtype=bool)\n\n    if finite.any():\n        finite_values = values[finite]\n        integer_like[finite] = np.abs(finite_values - np.round(finite_values)) <= EPSILON\n        one_decimal_like[finite] = np.abs(finite_values * 10.0 - np.round(finite_values * 10.0)) <= EPSILON\n        two_decimal_like[finite] = np.abs(finite_values * 100.0 - np.round(finite_values * 100.0)) <= EPSILON\n\n    integer_tier = integer_like\n    one_decimal_tier = one_decimal_like & ~integer_like\n    two_decimal_tier = two_decimal_like & ~one_decimal_like\n    finer_tier = finite & ~two_decimal_like\n\n    return integer_tier, one_decimal_tier, two_decimal_tier, finer_tier, finite\n\n\ndef _training_mask(raw):\n    if "id" not in raw.columns:\n        return pd.Series(True, index=raw.index)\n\n    ids = pd.to_numeric(raw["id"], errors="coerce")\n    mask = ids <= TRAIN_ID_MAX\n    if mask.any():\n        return mask.fillna(False)\n    return pd.Series(True, index=raw.index)\n\n\ndef _safe_fraction(numerator, denominator):\n    return np.divide(\n        numerator,\n        denominator,\n        out=np.zeros_like(numerator, dtype="float64"),\n        where=denominator > 0,\n    )\n\n\ndef add_report_granularity_clipping_signature(raw, deps, aux):\n    features = pd.DataFrame(index=raw.index)\n    train_mask = _training_mask(raw)\n\n    observed_count = np.zeros(len(raw), dtype="float64")\n    coarse_count = np.zeros(len(raw), dtype="float64")\n    integer_count = np.zeros(len(raw), dtype="float64")\n    tenth_count = np.zeros(len(raw), dtype="float64")\n    hundredth_count = np.zeros(len(raw), dtype="float64")\n    fine_count = np.zeros(len(raw), dtype="float64")\n\n    boundary_hit_count = np.zeros(len(raw), dtype="float64")\n    outside_count = np.zeros(len(raw), dtype="float64")\n    pressure_sum = np.zeros(len(raw), dtype="float64")\n    pressure_max = np.zeros(len(raw), dtype="float64")\n\n    for column in NUMERIC_COLUMNS:\n        series = _as_numeric_series(raw, column)\n        finite = series.notna().to_numpy()\n        observed_count += finite.astype("float64")\n\n        if column == "sleep_duration":\n            coarse = _is_multiple(series, 0.5).to_numpy()\n            features[column + "_whole_hour_heap"] = _is_multiple(series, 1.0).astype("int8")\n            features[column + "_half_hour_heap"] = coarse.astype("int8")\n        elif column == "heart_rate":\n            coarse = _is_multiple(series, 5.0).to_numpy()\n            features[column + "_multiple_5_heap"] = coarse.astype("int8")\n            features[column + "_multiple_10_heap"] = _is_multiple(series, 10.0).astype("int8")\n        elif column == "bmi":\n            coarse = _is_multiple(series, 0.5).to_numpy()\n            features[column + "_whole_heap"] = _is_multiple(series, 1.0).astype("int8")\n            features[column + "_half_heap"] = coarse.astype("int8")\n            features[column + "_one_decimal_heap"] = _is_multiple(series, 0.1).astype("int8")\n        elif column == "calorie_expenditure":\n            coarse = _is_multiple(series, 50.0).to_numpy()\n            features[column + "_multiple_50_heap"] = coarse.astype("int8")\n            features[column + "_multiple_100_heap"] = _is_multiple(series, 100.0).astype("int8")\n        elif column == "step_count":\n            coarse = _is_multiple(series, 500.0).to_numpy()\n            features[column + "_multiple_500_heap"] = coarse.astype("int8")\n            features[column + "_multiple_1000_heap"] = _is_multiple(series, 1000.0).astype("int8")\n        elif column == "exercise_duration":\n            coarse = _is_multiple(series, 5.0).to_numpy()\n            features[column + "_multiple_5_heap"] = coarse.astype("int8")\n            features[column + "_multiple_10_heap"] = _is_multiple(series, 10.0).astype("int8")\n            features[column + "_multiple_30_heap"] = _is_multiple(series, 30.0).astype("int8")\n        else:\n            coarse = _is_multiple(series, 0.25).to_numpy()\n            features[column + "_quarter_liter_heap"] = coarse.astype("int8")\n            features[column + "_half_liter_heap"] = _is_multiple(series, 0.5).astype("int8")\n\n        coarse_count += (coarse & finite).astype("float64")\n\n        integer_tier, one_decimal_tier, two_decimal_tier, finer_tier, finite_tier = _decimal_tiers(series)\n        features[column + "_precision_integer"] = integer_tier.astype("int8")\n        features[column + "_precision_one_decimal"] = one_decimal_tier.astype("int8")\n        features[column + "_precision_two_decimal"] = two_decimal_tier.astype("int8")\n        features[column + "_precision_finer"] = finer_tier.astype("int8")\n\n        integer_count += integer_tier.astype("float64")\n        tenth_count += one_decimal_tier.astype("float64")\n        hundredth_count += two_decimal_tier.astype("float64")\n        fine_count += finer_tier.astype("float64")\n\n        train_values = series.loc[train_mask & series.notna()]\n        if train_values.empty:\n            lower = np.nan\n            upper = np.nan\n            iqr = np.nan\n        else:\n            lower = float(train_values.min())\n            upper = float(train_values.max())\n            q1 = float(train_values.quantile(0.25))\n            q3 = float(train_values.quantile(0.75))\n            iqr = q3 - q1\n\n        values = series.to_numpy(dtype="float64", copy=False)\n        if np.isfinite(lower) and np.isfinite(upper):\n            train_range = upper - lower\n            scale = max(0.02 * train_range, 0.05 * iqr if np.isfinite(iqr) else 0.0, EPSILON)\n            lower_hit = finite & (np.abs(values - lower) <= EPSILON)\n            upper_hit = finite & (np.abs(values - upper) <= EPSILON)\n            outside = finite & ((values < lower) | (values > upper))\n            distance_to_bound = np.minimum(np.abs(values - lower), np.abs(values - upper))\n            pressure = np.clip(1.0 - distance_to_bound / scale, 0.0, 1.0)\n            pressure = np.where(finite, pressure, 0.0)\n            pressure = np.where(outside, 1.0, pressure)\n        else:\n            lower_hit = np.zeros(len(raw), dtype=bool)\n            upper_hit = np.zeros(len(raw), dtype=bool)\n            outside = np.zeros(len(raw), dtype=bool)\n            pressure = np.zeros(len(raw), dtype="float64")\n\n        features[column + "_train_lower_bound_hit"] = lower_hit.astype("int8")\n        features[column + "_train_upper_bound_hit"] = upper_hit.astype("int8")\n        features[column + "_outside_train_envelope"] = outside.astype("int8")\n        features[column + "_boundary_pressure"] = pressure.astype("float32")\n\n        boundary_hit_count += (lower_hit | upper_hit).astype("float64")\n        outside_count += outside.astype("float64")\n        pressure_sum += pressure\n        pressure_max = np.maximum(pressure_max, pressure)\n\n    features["observed_numeric_count"] = observed_count.astype("float32")\n    features["coarse_heaped_fraction"] = _safe_fraction(coarse_count, observed_count).astype("float32")\n    features["integer_like_fraction"] = _safe_fraction(integer_count, observed_count).astype("float32")\n    features["tenth_like_fraction"] = _safe_fraction(tenth_count, observed_count).astype("float32")\n    features["hundredth_like_fraction"] = _safe_fraction(hundredth_count, observed_count).astype("float32")\n    features["fine_grained_fraction"] = _safe_fraction(fine_count, observed_count).astype("float32")\n    features["boundary_hit_count"] = boundary_hit_count.astype("float32")\n    features["outside_train_envelope_count"] = outside_count.astype("float32")\n    features["max_boundary_pressure"] = pressure_max.astype("float32")\n    features["mean_boundary_pressure"] = _safe_fraction(pressure_sum, observed_count).astype("float32")\n\n    return features\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "report_granularity_clipping_signature",\n        "fn": add_report_granularity_clipping_signature,\n        "depends_on": [],\n        "description": "Measurement granularity, heaping, and train-boundary clipping signatures for raw student health measurements.",\n    }\n]'

HYPOTHESIS_000020_AUTOGLUON_001_PY_E8108C1E7D_SOURCE = 'import numpy as np\nimport pandas as pd\n\n\nTRAIN_ID_MAX = 690087\nSLEEP_NORMAL_MIN = 7.0\nSLEEP_NORMAL_MAX = 9.0\nSLEEP_SEVERE_SHORT_MAX = 5.0\nSLEEP_SHORT_MAX = 7.0\nBMI_UNDER_MAX = 18.5\nBMI_NORMAL_MAX = 25.0\nBMI_OVER_MAX = 30.0\nQUALITY_PENALTY_MAP = {\n    "good": 0.0,\n    "average": 0.5,\n    "poor": 1.0,\n}\n\n\ndef _training_mask(raw):\n    if "id" not in raw.columns:\n        return pd.Series(True, index=raw.index)\n\n    ids = pd.to_numeric(raw["id"], errors="coerce")\n    mask = ids <= TRAIN_ID_MAX\n    if mask.any():\n        return mask.fillna(False)\n\n    return pd.Series(True, index=raw.index)\n\n\ndef _train_quantile(series, train_mask, q, fallback):\n    values = pd.to_numeric(series, errors="coerce")\n    train_values = values.loc[train_mask].dropna()\n    if train_values.empty:\n        return fallback\n    result = train_values.quantile(q)\n    if pd.isna(result):\n        return fallback\n    return float(result)\n\n\ndef _train_median(series, train_mask, fallback):\n    values = pd.to_numeric(series, errors="coerce")\n    train_values = values.loc[train_mask].dropna()\n    if train_values.empty:\n        return fallback\n    result = train_values.median()\n    if pd.isna(result):\n        return fallback\n    return float(result)\n\n\ndef add_sleep_strain_echo(raw, deps, aux):\n    index = raw.index\n    train_mask = _training_mask(raw)\n\n    sleep_raw = pd.to_numeric(raw.get("sleep_duration"), errors="coerce")\n    heart_raw = pd.to_numeric(raw.get("heart_rate"), errors="coerce")\n    bmi_raw = pd.to_numeric(raw.get("bmi"), errors="coerce")\n    step_raw = pd.to_numeric(raw.get("step_count"), errors="coerce")\n    exercise_raw = pd.to_numeric(raw.get("exercise_duration"), errors="coerce")\n\n    sleep_median = _train_median(sleep_raw, train_mask, SLEEP_NORMAL_MIN)\n    heart_median = _train_median(heart_raw, train_mask, 75.0)\n    bmi_median = _train_median(bmi_raw, train_mask, 22.0)\n    step_median = _train_median(step_raw, train_mask, 7000.0)\n    exercise_median = _train_median(exercise_raw, train_mask, 30.0)\n\n    heart_q75 = _train_quantile(heart_raw, train_mask, 0.75, heart_median)\n    heart_q90 = _train_quantile(heart_raw, train_mask, 0.90, heart_q75)\n    step_q25 = _train_quantile(step_raw, train_mask, 0.25, step_median)\n    step_q75 = _train_quantile(step_raw, train_mask, 0.75, step_median)\n    exercise_q25 = _train_quantile(exercise_raw, train_mask, 0.25, exercise_median)\n    exercise_q75 = _train_quantile(exercise_raw, train_mask, 0.75, exercise_median)\n\n    sleep = sleep_raw.fillna(sleep_median)\n    heart = heart_raw.fillna(heart_median)\n    bmi = bmi_raw.fillna(bmi_median)\n    step = step_raw.fillna(step_median)\n    exercise = exercise_raw.fillna(exercise_median)\n\n    quality = raw.get("sleep_quality")\n    if quality is None:\n        quality_normalized = pd.Series("average", index=index)\n    else:\n        quality_normalized = quality.astype("string").str.lower().str.strip()\n\n    quality_penalty = quality_normalized.map(QUALITY_PENALTY_MAP).fillna(0.5).astype(float)\n    quality_bad_flag = (quality_penalty >= 1.0).astype(int)\n\n    sleep_debt = (SLEEP_NORMAL_MIN - sleep).clip(lower=0.0)\n    sleep_excess = (sleep - SLEEP_NORMAL_MAX).clip(lower=0.0)\n    rest_deficit = sleep_debt.clip(upper=3.0) + 0.5 * sleep_excess.clip(upper=2.0) + quality_penalty\n\n    pulse_tail = pd.Series(0.0, index=index)\n    if heart_q90 > heart_q75:\n        pulse_tail = pulse_tail.mask(heart >= heart_q75, 0.5)\n        pulse_tail = pulse_tail.mask(heart >= heart_q90, 1.0)\n    else:\n        pulse_tail = pulse_tail.mask(heart > heart_q75, 1.0)\n\n    bmi_tail = pd.Series(0.0, index=index)\n    bmi_tail = bmi_tail.mask(((bmi >= 16.0) & (bmi < BMI_UNDER_MAX)) | ((bmi >= BMI_NORMAL_MAX) & (bmi < BMI_OVER_MAX)), 0.5)\n    bmi_tail = bmi_tail.mask(bmi >= BMI_OVER_MAX, 1.0)\n\n    exertion_high = ((step >= step_q75) | (exercise >= exercise_q75)).astype(float)\n    exertion_low = ((step <= step_q25) & (exercise <= exercise_q25)).astype(float)\n\n    numeric_context_missing = sleep_raw.isna() & heart_raw.isna() & bmi_raw.isna() & step_raw.isna() & exercise_raw.isna()\n    pulse_tail = pulse_tail.mask(numeric_context_missing, 0.0)\n    bmi_tail = bmi_tail.mask(numeric_context_missing, 0.0)\n    exertion_high = exertion_high.mask(numeric_context_missing, 0.0)\n    exertion_low = exertion_low.mask(numeric_context_missing, 0.0)\n\n    sleep_band = pd.Series("normal", index=index, dtype="object")\n    sleep_band = sleep_band.mask(sleep < SLEEP_SEVERE_SHORT_MAX, "severe_short")\n    sleep_band = sleep_band.mask((sleep >= SLEEP_SEVERE_SHORT_MAX) & (sleep < SLEEP_SHORT_MAX), "short")\n    sleep_band = sleep_band.mask(sleep > SLEEP_NORMAL_MAX, "long")\n    sleep_band = sleep_band.mask(sleep_raw.isna(), "missing")\n\n    high_physio_strain = ((pulse_tail + bmi_tail) >= 1.0).astype(int)\n    normal_sleep = (sleep >= SLEEP_NORMAL_MIN) & (sleep <= SLEEP_NORMAL_MAX)\n    good_quality = quality_penalty == 0.0\n\n    restorative_alignment = (\n        normal_sleep\n        & good_quality\n        & (bmi_tail == 0.0)\n        & (pulse_tail == 0.0)\n        & (~numeric_context_missing)\n    ).astype(int)\n\n    phenotype_code = (\n        sleep_band.astype(str)\n        + "_qbad"\n        + quality_bad_flag.astype(str)\n        + "_strain"\n        + high_physio_strain.astype(str)\n    )\n\n    features = pd.DataFrame(index=index)\n    features["rest_deficit"] = rest_deficit.astype(float)\n    features["sleep_physio_echo"] = (rest_deficit * (pulse_tail + bmi_tail)).astype(float)\n    features["sleep_exertion_overreach"] = (rest_deficit * pulse_tail * exertion_high).astype(float)\n    features["quiet_sleep_deficit"] = (rest_deficit * (1.0 - pulse_tail) * (1.0 - bmi_tail)).astype(float)\n    features["restorative_alignment"] = restorative_alignment.astype(int)\n    features["sleep_strain_phenotype"] = phenotype_code.astype("string")\n    features["sleep_band"] = sleep_band.astype("string")\n    features["pulse_tail"] = pulse_tail.astype(float)\n    features["bmi_tail"] = bmi_tail.astype(float)\n    features["exertion_high"] = exertion_high.astype(float)\n    features["exertion_low"] = exertion_low.astype(float)\n\n    return features\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "sleep_strain_echo",\n        "fn": add_sleep_strain_echo,\n        "depends_on": [],\n        "description": "Sleep quantity and perceived quality features coupled with pulse, BMI, and exertion strain.",\n    }\n]'

HYPOTHESIS_000034_AUTOGLUON_001_PY_FF46EEDE3F_SOURCE = 'import numpy as np\nimport pandas as pd\n\n\nNUMERIC_COLUMNS = (\n    "sleep_duration",\n    "heart_rate",\n    "bmi",\n    "calorie_expenditure",\n    "step_count",\n    "exercise_duration",\n    "water_intake",\n)\n\nDEMAND_COLUMNS = (\n    "calorie_expenditure",\n    "step_count",\n    "exercise_duration",\n)\n\nTRAIN_ID_MAX = 690087\n\nSLEEP_QUALITY_SCORES = {\n    "poor": 0.0,\n    "average": 0.5,\n    "good": 1.0,\n}\n\nSTRESS_LEVEL_SCORES = {\n    "high": 0.0,\n    "medium": 0.5,\n    "low": 1.0,\n}\n\nDIET_BALANCE_SCORES = {\n    "non-veg": 0.35,\n    "veg": 0.65,\n    "balanced": 1.0,\n}\n\n\ndef _numeric(raw, column):\n    if column not in raw.columns:\n        return pd.Series(np.nan, index=raw.index, dtype="float64")\n    return pd.to_numeric(raw[column], errors="coerce").astype("float64")\n\n\ndef _category_score(raw, column, mapping, neutral):\n    if column not in raw.columns:\n        return pd.Series(neutral, index=raw.index, dtype="float64")\n    values = raw[column].astype("string").str.lower().str.strip()\n    return values.map(mapping).astype("float64").fillna(neutral)\n\n\ndef _stats_frame(raw):\n    if "id" not in raw.columns:\n        return raw\n\n    ids = pd.to_numeric(raw["id"], errors="coerce")\n    train_like = ids.le(TRAIN_ID_MAX)\n    if train_like.any():\n        return raw.loc[train_like]\n\n    return raw\n\n\ndef _median_from(frame, column, fallback):\n    values = pd.to_numeric(frame[column], errors="coerce") if column in frame.columns else pd.Series(dtype="float64")\n    median = values.median(skipna=True)\n    if pd.isna(median):\n        return fallback\n    return float(median)\n\n\ndef _percentile_rank(values, reference_values):\n    clean_ref = pd.to_numeric(reference_values, errors="coerce").dropna().sort_values()\n    filled = values.fillna(clean_ref.median() if len(clean_ref) else 0.0)\n\n    if len(clean_ref) < 2:\n        return pd.Series(0.5, index=values.index, dtype="float64")\n\n    ranks = np.searchsorted(clean_ref.to_numpy(), filled.to_numpy(), side="right") / float(len(clean_ref))\n    return pd.Series(ranks, index=values.index, dtype="float64").clip(0.0, 1.0)\n\n\ndef add_energy_availability_phase(raw, deps, aux):\n    stats = _stats_frame(raw)\n\n    sleep = _numeric(raw, "sleep_duration")\n    heart_rate = _numeric(raw, "heart_rate")\n    bmi = _numeric(raw, "bmi")\n    calories = _numeric(raw, "calorie_expenditure")\n    steps = _numeric(raw, "step_count")\n    exercise = _numeric(raw, "exercise_duration")\n    water = _numeric(raw, "water_intake")\n\n    sleep_filled = sleep.fillna(_median_from(stats, "sleep_duration", 7.5))\n    heart_rate_filled = heart_rate.fillna(_median_from(stats, "heart_rate", 72.0))\n    bmi_filled = bmi.fillna(_median_from(stats, "bmi", 22.5))\n    water_filled = water.fillna(_median_from(stats, "water_intake", 2.2))\n\n    calorie_pct = _percentile_rank(calories, stats["calorie_expenditure"] if "calorie_expenditure" in stats.columns else calories)\n    step_pct = _percentile_rank(steps, stats["step_count"] if "step_count" in stats.columns else steps)\n    exercise_pct = _percentile_rank(exercise, stats["exercise_duration"] if "exercise_duration" in stats.columns else exercise)\n    heart_rate_pct = _percentile_rank(heart_rate, stats["heart_rate"] if "heart_rate" in stats.columns else heart_rate)\n\n    all_demand_missing = calories.isna() & steps.isna() & exercise.isna()\n    demand_score = pd.concat((calorie_pct, step_pct, exercise_pct), axis=1).mean(axis=1).clip(0.0, 1.0)\n    demand_score = demand_score.mask(all_demand_missing, 0.5)\n\n    sleep_band_support = (1.0 - ((sleep_filled - 8.0).abs() / 2.5)).clip(0.0, 1.0)\n    water_support = ((water_filled - 1.0) / 2.0).clip(0.0, 1.0)\n    sleep_quality_support = _category_score(raw, "sleep_quality", SLEEP_QUALITY_SCORES, 0.5)\n    stress_support = _category_score(raw, "stress_level", STRESS_LEVEL_SCORES, 0.5)\n    diet_support = _category_score(raw, "diet_type", DIET_BALANCE_SCORES, 0.5)\n\n    recovery_support = pd.concat(\n        (\n            sleep_band_support,\n            water_support,\n            sleep_quality_support,\n            stress_support,\n            diet_support,\n        ),\n        axis=1,\n    ).mean(axis=1).clip(0.0, 1.0)\n\n    weak_recovery = (1.0 - recovery_support).clip(0.0, 1.0)\n    low_bmi_margin = ((18.5 - bmi_filled) / 2.5).clip(0.0, 1.0)\n    healthy_bmi_band = np.minimum((bmi_filled - 18.5) / 2.0, (25.0 - bmi_filled) / 3.0)\n    healthy_bmi_band = pd.Series(healthy_bmi_band, index=raw.index, dtype="float64").clip(0.0, 1.0)\n    high_bmi_margin = ((bmi_filled - 25.0) / 7.5).clip(0.0, 1.0)\n\n    elevated_hr = heart_rate_pct.clip(0.0, 1.0)\n    non_elevated_hr = (1.0 - elevated_hr).clip(0.0, 1.0)\n\n    demand_minus_support_gap = (demand_score - recovery_support).clip(-1.0, 1.0)\n    under_supported_exertion_pressure = (\n        demand_score * 0.35\n        + weak_recovery * 0.25\n        + low_bmi_margin * 0.20\n        + elevated_hr * 0.20\n    ).clip(0.0, 1.0)\n    low_throughput_surplus_pressure = (\n        high_bmi_margin * 0.40\n        + (1.0 - demand_score).clip(0.0, 1.0) * 0.30\n        + weak_recovery * 0.30\n    ).clip(0.0, 1.0)\n    supported_high_throughput_score = (\n        demand_score * 0.35\n        + healthy_bmi_band * 0.25\n        + recovery_support * 0.25\n        + non_elevated_hr * 0.15\n    ).clip(0.0, 1.0)\n\n    pressure_stack = pd.concat(\n        (\n            under_supported_exertion_pressure.rename("under_supported_exertion"),\n            low_throughput_surplus_pressure.rename("low_throughput_surplus"),\n            supported_high_throughput_score.rename("supported_high_throughput"),\n        ),\n        axis=1,\n    )\n    phase_label = pressure_stack.idxmax(axis=1).astype("object")\n    phase_label = phase_label.mask(pressure_stack.max(axis=1).lt(0.45), "neutral")\n\n    return pd.DataFrame(\n        {\n            "activity_demand_score": demand_score.astype("float32"),\n            "recovery_support_score": recovery_support.astype("float32"),\n            "demand_minus_support_gap": demand_minus_support_gap.astype("float32"),\n            "low_bmi_reserve_deficit": low_bmi_margin.astype("float32"),\n            "healthy_bmi_band": healthy_bmi_band.astype("float32"),\n            "high_bmi_surplus_margin": high_bmi_margin.astype("float32"),\n            "heart_rate_percentile": heart_rate_pct.astype("float32"),\n            "under_supported_exertion_pressure": under_supported_exertion_pressure.astype("float32"),\n            "low_throughput_surplus_pressure": low_throughput_surplus_pressure.astype("float32"),\n            "supported_high_throughput_score": supported_high_throughput_score.astype("float32"),\n            "energy_availability_phase": phase_label.astype("category"),\n            "all_demand_inputs_missing": all_demand_missing.astype("int8"),\n        },\n        index=raw.index,\n    )\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "energy_availability_phase",\n        "fn": add_energy_availability_phase,\n        "depends_on": [],\n        "description": "Energy availability phase features combining activity demand, recovery support, body context, and heart-rate strain.",\n    }\n]'

